def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(start_pos, end_pos):
        return np.linalg.norm(start_pos - end_pos)

    best_node = None
    min_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = dist_to_customer / truck_speed

        duration_time_window = time_windows[idx][1] - time_windows[idx][0]
        waiting_time = max(0, time_windows[idx][0] - (current_time + travel_time))

        cost = dist_to_customer / truck_speed + waiting_time * 2

        if duration_time_window < cost:
            cost = duration_time_window

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node
